import { createClient } from '@shared/utils/supabase/server';
import { Project, NewProjectInput, Phase } from '@shared/types/project';
import { Task } from '@shared/types/task';

export async function createProject(input: Omit<NewProjectInput, 'user_id'>): Promise<Project> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) throw new Error("Unauthorized");

    const payload: NewProjectInput = {
        ...input,
        user_id: user.id,
    };

    const { data, error } = await supabase
        .from('projects')
        .insert([payload])
        .select()
        .single();

    if (error) {
        console.error('Error creating project:', error);
        throw new Error('Failed to create project');
    }

    return data as Project;
}

export async function getProjects(userId: string): Promise<Project[]> {
    const supabase = await createClient();

    const { data, error } = await supabase
        .from('projects')
        .select('*')
        .or(`is_demo_project.eq.true,user_id.eq.${userId}`)
        .order('created_at', { ascending: false });

    if (error) {
        console.error('Error fetching projects:', error);
        return [];
    }

    return data as Project[];
}

export async function getProject(project_id: string): Promise<{ project: Project, phases: Phase[], tasks: Task[] }> {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) throw new Error("Unauthorized");

    const { data: project, error: pError } = await supabase
        .from('projects')
        .select('*')
        .eq('id', project_id)
        .or(`is_demo_project.eq.true,user_id.eq.${user.id}`) // Security enforcement
        .single();

    if (pError || !project) throw new Error(`Failed to fetch project or unauthorized`);

    const { data: phases, error: phError } = await supabase
        .from('phases')
        .select('*')
        .eq('project_id', project_id)
        .order('phase_order', { ascending: true });

    if (phError) throw new Error(`Failed to fetch phases: ${phError.message}`);

    const phaseIds = phases ? phases.map(p => p.id) : [];

    let tasks: Task[] = [];
    if (phaseIds.length > 0) {
        const { data: tData, error: tError } = await supabase
            .from('tasks')
            .select('*')
            .in('phase_id', phaseIds)
            .order('task_order', { ascending: true });

        if (tError) throw new Error(`Failed to fetch tasks: ${tError.message}`);
        tasks = tData as Task[];
    }

    return { project: project as Project, phases: phases as Phase[], tasks };
}
